// Unihan IRG Source flags for CJK characters
// Generated from Unicode 17.0.0 Unihan_IRGSources.txt
// Bit flags: J=1, G=2, T=4, K=8 (4 bits per character, packed as nibbles)
// 88228 characters across 11 blocks, 50340 bytes

const CJK_IRG_BLOCKS: readonly [number, number][] = [[13312,19903],[19968,40959],[63744,64255],[131072,173791],[173824,177977],[177984,178205],[178208,183983],[183984,191471],[191472,194559],[196608,201551],[201552,205743]];

// prettier-ignore
const CJK_IRG_DATA = "";

let irgBytes: Uint8Array | null = null;

function getIrgBytes(): Uint8Array {
  if (!irgBytes) {
    const bin = atob(CJK_IRG_DATA);
    irgBytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) irgBytes[i] = bin.charCodeAt(i);
  }
  return irgBytes;
}

/**
 * Get CJK IRG source flags for a code point.
 * Returns a bitmask: J=1, G=2, T=4, K=8. Returns 0 if not in any CJK block.
 */
export function getCjkIrgFlags(cp: number): number {
  const bytes = getIrgBytes();
  let byteOffset = 0;
  for (const [start, end] of CJK_IRG_BLOCKS) {
    const blockSize = end - start + 1;
    const blockBytes = Math.ceil(blockSize / 2);
    if (cp >= start && cp <= end) {
      const idx = cp - start;
      const b = bytes[byteOffset + (idx >> 1)];
      return (idx % 2 === 0) ? (b & 0x0f) : (b >> 4);
    }
    byteOffset += blockBytes;
  }
  return 0;
}
